let STAGES = [];
let STAGE_ICONS = [];
function syncStageArrays(){
  STAGES = state.stages.map(s=>s.label);
  STAGE_ICONS = state.stages.map(s=>s.icon);
}

// إرجاع حالات السيارة الخاصة بها أو الافتراضية
function getCarStages(car){
  if(car&&car.stages&&car.stages.length) return car.stages;
  return state.stages;
}

function loadState(){
  try{const s=localStorage.getItem('finaltouchv2');if(s){const p=JSON.parse(s);state={...state,...p};
    if(!state.stages||!state.stages.length)state.stages=[{icon:'📋',label:'استلام'},{icon:'🔍',label:'تشخيص'},{icon:'🔧',label:'إصلاح'},{icon:'🎨',label:'دهان'},{icon:'✅',label:'جاهزة للتسليم'},{icon:'📦',label:'تسليم'}];
    if(!state.stageTemplates)state.stageTemplates={};
    if(!state.serviceTypes||!state.serviceTypes.length)state.serviceTypes=['صيانة','سمكرة','دهان','كهرباء','أخرى'];
    if(!state.monthlyClosings)state.monthlyClosings=[];
  }}catch(e){}
}
function saveState(){localStorage.setItem('finaltouchv2',JSON.stringify(state));}
loadState();
syncStageArrays();

const fmt=(n)=>parseFloat(n||0).toFixed(3)+' ر.ع';
const today=()=>new Date().toISOString().split('T')[0];
const genId=()=>Date.now()+Math.random().toString(36).substr(2,5);
function formatDate(d){if(!d)return'—';return new Date(d).toLocaleDateString('ar-SA',{year:'numeric',month:'short',day:'numeric'});}
function daysSince(d){if(!d)return 0;return Math.floor((Date.now()-new Date(d))/(1000*60*60*24));}

function statusBadge(s){
  return {waiting:'<span class="badge badge-waiting">⏳ انتظار</span>',progress:'<span class="badge badge-progress">🔧 إصلاح</span>',done:'<span class="badge badge-done">✅ جاهزة</span>',delivered:'<span class="badge badge-delivered">📦 مُسلَّمة</span>'}[s]||s;
}
function serviceBadge(s){
  if(!s)return'—';
  if(s.includes('دهان'))return`<span class="badge badge-paint">🎨 ${s}</span>`;
  if(s.includes('سمكرة'))return`<span class="badge badge-body">🔨 ${s}</span>`;
  return`<span class="badge badge-maint">🔧 ${s}</span>`;
}
function stageFromStatus(s,stages){const arr=stages||state.stages;const last=arr.length-1;return{waiting:0,progress:Math.min(2,last),done:Math.max(0,last-1),delivered:last}[s]||0;}
function statusFromStage(i,stages){const last=(stages||state.stages).length-1;return i>=last?'delivered':i>=(last-1)?'done':i>=1?'progress':'waiting';}

