// ── IndexedDB: open and migrate on start ─────────────────────────
(function initIDB() {
  if (typeof db !== 'undefined' && db.open) {
    db.open().then(() => db.migrateFromLocalStorage()).catch(e => console.warn('[IDB init]', e));
  }
})();
